import{_ as e,o as s,c as t,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"远程访问","description":"","frontmatter":{"read_when":["运行或排查远程 Gateway 网关设置问题"],"summary":"使用 SSH 隧道（Gateway WS）和 tailnet 进行远程访问","title":"远程访问","x-i18n":{"generated_at":"2026-02-03T07:48:40Z","model":"claude-opus-4-5","provider":"pi","source_hash":"7e00bd2e048dfbd829913bef0f40a791b8d8c3e2f8a115fc0a13b03f136ebc93","source_path":"gateway/remote.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/remote.md","filePath":"zh-CN/gateway/remote.md","lastUpdated":1771906665000}'),l={name:"zh-CN/gateway/remote.md"};function n(o,a,r,p,h,c){return s(),t("div",null,[...a[0]||(a[0]=[i(`<h1 id="远程访问-ssh、隧道和-tailnet" tabindex="-1"><a class="header-anchor" href="#远程访问-ssh、隧道和-tailnet">#</a> 远程访问（SSH、隧道和 tailnet）</h1><p>本仓库通过在专用主机（桌面/服务器）上运行单个 Gateway 网关（主节点）并让客户端连接到它来支持&quot;SSH 远程&quot;。</p><ul><li>对于<strong>操作员（你/macOS 应用）</strong>：SSH 隧道是通用的回退方案。</li><li>对于<strong>节点（iOS/Android 和未来的设备）</strong>：连接到 Gateway <strong>WebSocket</strong>（LAN/tailnet 或根据需要通过 SSH 隧道）。</li></ul><h2 id="核心理念" tabindex="-1"><a class="header-anchor" href="#核心理念">#</a> 核心理念</h2><ul><li>Gateway WebSocket 绑定到你配置端口的 <strong>loopback</strong>（默认为 18789）。</li><li>对于远程使用，你通过 SSH 转发该 loopback 端口（或使用 tailnet/VPN 减少隧道需求）。</li></ul><h2 id="常见的-vpn-tailnet-设置-智能体所在位置" tabindex="-1"><a class="header-anchor" href="#常见的-vpn-tailnet-设置-智能体所在位置">#</a> 常见的 VPN/tailnet 设置（智能体所在位置）</h2><p>将 <strong>Gateway 网关主机</strong>视为&quot;智能体所在的位置&quot;。它拥有会话、身份验证配置文件、渠道和状态。 你的笔记本电脑/桌面（和节点）连接到该主机。</p><h3 id="_1-tailnet-中始终在线的-gateway-网关-vps-或家庭服务器" tabindex="-1"><a class="header-anchor" href="#_1-tailnet-中始终在线的-gateway-网关-vps-或家庭服务器">#</a> 1) tailnet 中始终在线的 Gateway 网关（VPS 或家庭服务器）</h3><p>在持久主机上运行 Gateway 网关，并通过 <strong>Tailscale</strong> 或 SSH 访问它。</p><ul><li><strong>最佳用户体验：</strong> 保持 <code>gateway.bind: &quot;loopback&quot;</code> 并使用 <strong>Tailscale Serve</strong> 作为控制 UI。</li><li><strong>回退方案：</strong> 保持 loopback + 从任何需要访问的机器建立 SSH 隧道。</li><li><strong>示例：</strong> <a href="/docs/install/exe-dev">exe.dev</a>（简易 VM）或 <a href="/docs/install/hetzner">Hetzner</a>（生产 VPS）。</li></ul><p>当你的笔记本电脑经常休眠但你希望智能体始终在线时，这是理想的选择。</p><h3 id="_2-家庭桌面运行-gateway-网关-笔记本电脑作为远程控制" tabindex="-1"><a class="header-anchor" href="#_2-家庭桌面运行-gateway-网关-笔记本电脑作为远程控制">#</a> 2) 家庭桌面运行 Gateway 网关，笔记本电脑作为远程控制</h3><p>笔记本电脑<strong>不</strong>运行智能体。它远程连接：</p><ul><li>使用 macOS 应用的 <strong>Remote over SSH</strong> 模式（设置 → 通用 → &quot;OpenSoul runs&quot;）。</li><li>应用打开并管理隧道，因此 WebChat + 健康检查&quot;直接工作&quot;。</li></ul><p>操作手册：<a href="/docs/platforms/mac/remote">macOS 远程访问</a>。</p><h3 id="_3-笔记本电脑运行-gateway-网关-从其他机器远程访问" tabindex="-1"><a class="header-anchor" href="#_3-笔记本电脑运行-gateway-网关-从其他机器远程访问">#</a> 3) 笔记本电脑运行 Gateway 网关，从其他机器远程访问</h3><p>保持 Gateway 网关在本地但安全地暴露它：</p><ul><li>从其他机器到笔记本电脑的 SSH 隧道，或</li><li>Tailscale Serve 控制 UI 并保持 Gateway 网关仅 loopback。</li></ul><p>指南：<a href="/docs/gateway/tailscale">Tailscale</a> 和 <a href="/docs/web/index">Web 概览</a>。</p><h2 id="命令流-什么在哪里运行" tabindex="-1"><a class="header-anchor" href="#命令流-什么在哪里运行">#</a> 命令流（什么在哪里运行）</h2><p>一个 Gateway 网关服务拥有状态 + 渠道。节点是外围设备。</p><p>流程示例（Telegram → 节点）：</p><ul><li>Telegram 消息到达 <strong>Gateway 网关</strong>。</li><li>Gateway 网关运行<strong>智能体</strong>并决定是否调用节点工具。</li><li>Gateway 网关通过 Gateway WebSocket 调用<strong>节点</strong>（<code>node.*</code> RPC）。</li><li>节点返回结果；Gateway 网关回复到 Telegram。</li></ul><p>说明：</p><ul><li><strong>节点不运行 Gateway 网关服务。</strong> 除非你有意运行隔离的配置文件，否则每台主机只应运行一个 Gateway 网关（参见<a href="/docs/gateway/multiple-gateways">多 Gateway 网关</a>）。</li><li>macOS 应用的&quot;节点模式&quot;只是通过 Gateway WebSocket 的节点客户端。</li></ul><h2 id="ssh-隧道-cli-工具" tabindex="-1"><a class="header-anchor" href="#ssh-隧道-cli-工具">#</a> SSH 隧道（CLI + 工具）</h2><p>创建到远程 Gateway WS 的本地隧道：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -N</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 18789:127.0.0.1:18789</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@host</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>隧道建立后：</p><ul><li><code>opensoul health</code> 和 <code>opensoul status --deep</code> 现在通过 <code>ws://127.0.0.1:18789</code> 访问远程 Gateway 网关。</li><li><code>opensoul gateway {status,health,send,agent,call}</code> 在需要时也可以通过 <code>--url</code> 指定转发的 URL。</li></ul><p>注意：将 <code>18789</code> 替换为你配置的 <code>gateway.port</code>（或 <code>--port</code>/<code>OPENSOUL_GATEWAY_PORT</code>）。</p><h2 id="cli-远程默认值" tabindex="-1"><a class="header-anchor" href="#cli-远程默认值">#</a> CLI 远程默认值</h2><p>你可以持久化远程目标，以便 CLI 命令默认使用它：</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  gateway</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    mode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;remote&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    remote</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ws://127.0.0.1:18789&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      token</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;your-token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>当 Gateway 网关仅限 loopback 时，保持 URL 为 <code>ws://127.0.0.1:18789</code> 并先打开 SSH 隧道。</p><h2 id="通过-ssh-的聊天-ui" tabindex="-1"><a class="header-anchor" href="#通过-ssh-的聊天-ui">#</a> 通过 SSH 的聊天 UI</h2><p>WebChat 不再使用单独的 HTTP 端口。SwiftUI 聊天 UI 直接连接到 Gateway WebSocket。</p><ul><li>通过 SSH 转发 <code>18789</code>（见上文），然后让客户端连接到 <code>ws://127.0.0.1:18789</code>。</li><li>在 macOS 上，优先使用应用的&quot;Remote over SSH&quot;模式，它会自动管理隧道。</li></ul><h2 id="macos-应用-remote-over-ssh" tabindex="-1"><a class="header-anchor" href="#macos-应用-remote-over-ssh">#</a> macOS 应用&quot;Remote over SSH&quot;</h2><p>macOS 菜单栏应用可以端到端驱动相同的设置（远程状态检查、WebChat 和语音唤醒转发）。</p><p>操作手册：<a href="/docs/platforms/mac/remote">macOS 远程访问</a>。</p><h2 id="安全规则-远程-vpn" tabindex="-1"><a class="header-anchor" href="#安全规则-远程-vpn">#</a> 安全规则（远程/VPN）</h2><p>简短版本：<strong>保持 Gateway 网关仅 loopback</strong>，除非你确定需要绑定。</p><ul><li><strong>Loopback + SSH/Tailscale Serve</strong> 是最安全的默认设置（无公开暴露）。</li><li><strong>非 loopback 绑定</strong>（<code>lan</code>/<code>tailnet</code>/<code>custom</code>，或当 loopback 不可用时的 <code>auto</code>）必须使用身份验证令牌/密码。</li><li><code>gateway.remote.token</code> <strong>仅</strong>用于远程 CLI 调用——它<strong>不</strong>启用本地身份验证。</li><li><code>gateway.remote.tlsFingerprint</code> 在使用 <code>wss://</code> 时固定远程 TLS 证书。</li><li>当 <code>gateway.auth.allowTailscale: true</code> 时，<strong>Tailscale Serve</strong> 可以通过身份标头进行身份验证。如果你想使用令牌/密码，请将其设置为 <code>false</code>。</li><li>将浏览器控制视为操作员访问：仅限 tailnet + 有意的节点配对。</li></ul><p>深入了解：<a href="/docs/gateway/security/index">安全</a>。</p>`,45)])])}const k=e(l,[["render",n]]);export{g as __pageData,k as default};
